let CART = JSON.parse(localStorage.getItem('fmd_cart') || '[]');
let USER = JSON.parse(localStorage.getItem('fmd_user') || 'null');

function saveCart(){localStorage.setItem('fmd_cart',JSON.stringify(CART));updateBadges()}
function saveUser(){localStorage.setItem('fmd_user',JSON.stringify(USER))}

function updateBadges(){
  const count = CART.reduce((s,i)=>s+i.qty,0);
  document.getElementById('cartBadge').textContent = count;
  document.getElementById('mbnBadge').textContent = count;
  document.getElementById('cartBadge').style.display = count > 0 ? 'block' : 'none';
  document.getElementById('mbnBadge').style.display = count > 0 ? 'block' : 'none';
}

function showToast(msg){
  const t = document.getElementById('toast');
  document.getElementById('toastMsg').textContent = msg;
  t.classList.add('show');
  setTimeout(()=>t.classList.remove('show'), 1800);
}

function getSvg(cat){
  if (cat==='inverter') return '<svg viewBox="0 0 100 100" fill="none"><rect x="20" y="15" width="60" height="75" rx="5" fill="#1E6BB8" stroke="#0B2545" stroke-width="2"/><rect x="28" y="22" width="44" height="20" fill="#061629" rx="2"/><text x="50" y="36" fill="#5DE0A0" font-family="Montserrat" font-size="6.5" font-weight="800" text-anchor="middle">HYBRID</text><rect x="32" y="80" width="36" height="5" fill="#F4B400" rx="1"/></svg>';
  if (cat==='battery') return '<svg viewBox="0 0 100 100" fill="none"><rect x="18" y="25" width="64" height="50" rx="4" fill="#27AE60" stroke="#0B2545" stroke-width="2"/><text x="50" y="55" fill="#5DE0A0" font-family="Montserrat" font-size="8" font-weight="800" text-anchor="middle">LITHIUM</text></svg>';
  if (cat==='panel') return '<svg viewBox="0 0 100 100" fill="none"><rect x="10" y="20" width="80" height="60" rx="3" fill="#1E6BB8" stroke="#0B2545" stroke-width="2"/><g stroke="#2E86DE" stroke-width=".8" opacity=".6"><line x1="30" y1="20" x2="30" y2="80"/><line x1="50" y1="20" x2="50" y2="80"/><line x1="70" y1="20" x2="70" y2="80"/><line x1="10" y1="40" x2="90" y2="40"/><line x1="10" y1="60" x2="90" y2="60"/></g></svg>';
  if (cat==='ceiling') return '<svg viewBox="0 0 100 100" fill="none"><circle cx="50" cy="50" r="38" fill="#F4B400" opacity=".2"/><circle cx="50" cy="50" r="18" fill="#FFD60A"/></svg>';
  if (cat==='wall') return '<svg viewBox="0 0 100 100" fill="none"><rect x="35" y="20" width="30" height="60" rx="3" fill="#0B2545"/><circle cx="50" cy="35" r="6" fill="#FFD60A"/></svg>';
  if (cat==='tech') return '<svg viewBox="0 0 100 100" fill="none"><rect x="20" y="25" width="60" height="50" rx="6" fill="#1E6BB8" stroke="#0B2545" stroke-width="2"/></svg>';
  return '<svg viewBox="0 0 100 100" fill="none"><circle cx="50" cy="50" r="30" fill="#F4B400"/></svg>';
}

function paintProductImages(){
  document.querySelectorAll('.prod-img[data-cat]').forEach(el=>{
    if (!el.querySelector('svg') && !el.querySelector('img')){
      el.insertAdjacentHTML('afterbegin', getSvg(el.dataset.cat) + '<span class="prod-stock">In Stock</span>');
    }
  });
}

function addToCart(pid, btn){
  const p = PRODUCTS[pid];
  if (!p) return;
  const existing = CART.find(i=>i.id===pid);
  if (existing) existing.qty++;
  else CART.push({id:pid, qty:1});
  saveCart();
  showToast('✓ ' + p.title.substring(0,40) + ' added');
  if (btn){
    const original = btn.innerHTML;
    btn.classList.add('added');
    btn.innerHTML = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" width="14" height="14"><path d="M5 13l4 4L19 7"/></svg>Added';
    setTimeout(()=>{ btn.classList.remove('added'); btn.innerHTML = original; }, 1500);
  }
}

function removeFromCart(pid){ CART = CART.filter(i=>i.id!==pid); saveCart(); renderCart(); }
function updateQty(pid, delta){
  const item = CART.find(i=>i.id===pid);
  if (!item) return;
  item.qty = Math.max(1, item.qty + delta);
  saveCart(); renderCart();
}

function renderCart(){
  const items = document.getElementById('cartItems');
  const summary = document.getElementById('cartSummary');
  if (CART.length === 0){
    items.innerHTML = '<div class="cart-empty"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4zM3 6h18M16 10a4 4 0 01-8 0"/></svg><h3>Your cart is empty</h3><p>Browse the shop and add products.</p><br><a href="javascript:void(0)" onclick="showPage(\'shop\')" class="btn btn-primary">Browse Shop</a></div>';
    summary.innerHTML = '';
    return;
  }
  let html = '';
  CART.forEach(i=>{
    const p = PRODUCTS[i.id];
    if (!p) return;
    const thumb = p.img ? '<img src="'+p.img+'" alt="" style="width:100%;height:100%;object-fit:contain">' : getSvg(p.cat);
    html += '<div class="cart-item"><div class="cart-thumb">' + thumb + '</div><div class="cart-info"><span class="brand">' + p.brand + '</span><strong>' + p.title + '</strong><span class="specs">' + p.specs + '</span></div><div class="cart-qty"><button onclick="updateQty(\''+i.id+'\',-1)">−</button><input type="number" value="' + i.qty + '" readonly><button onclick="updateQty(\''+i.id+'\',1)">+</button></div><div class="cart-line-price">R ' + (p.price*i.qty).toLocaleString() + '</div><button class="cart-remove" onclick="removeFromCart(\''+i.id+'\')"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" width="18" height="18"><path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg></button></div>';
  });
  items.innerHTML = html;
  const subtotal = CART.reduce((s,i)=>{const p=PRODUCTS[i.id];return s+(p?p.price*i.qty:0);}, 0);
  const totalQty = CART.reduce((s,i)=>s+i.qty,0);
  summary.innerHTML = '<h3>Order Summary</h3><div class="cart-summary-row"><span>Subtotal (' + totalQty + ' items)</span><strong>R ' + subtotal.toLocaleString() + '</strong></div><div class="cart-summary-row"><span>VAT</span><strong style="color:var(--grey-mid);font-size:.85rem">Included</strong></div><div class="cart-summary-row"><span>Delivery (Gauteng)</span><strong style="color:var(--green)">FREE</strong></div><div class="cart-summary-row total"><span>Total</span><strong>R ' + subtotal.toLocaleString() + '</strong></div><div class="checkout-info"><strong>How checkout works</strong>Click below to send your order via WhatsApp or email. FMD will confirm stock, finalise pricing, send EFT details. No payment taken online.</div><button onclick="checkoutWhatsApp()" class="btn btn-wa" style="width:100%;margin-bottom:.5rem;padding:1.1rem"><svg viewBox="0 0 32 32" width="18" height="18" fill="currentColor" style="margin-right:4px"><path d="M16.001 0C7.166 0 0 7.166 0 15.999c0 2.736.692 5.422 2.005 7.81L0 32l8.394-2.211a16.011 16.011 0 0 0 7.605 1.937h.001c8.835 0 15.999-7.166 15.999-15.999A15.85 15.85 0 0 0 27.32 4.682 15.84 15.84 0 0 0 16.001 0Z"/></svg>Send Order via WhatsApp</button><button onclick="checkoutEmail()" class="btn btn-dark" style="width:100%;margin-bottom:.5rem">📧 Email Order to FMD</button><a href="javascript:void(0)" onclick="showPage(\'shop\')" class="btn btn-outline" style="width:100%">← Continue Shopping</a>';
}

function checkoutWhatsApp(){
  if (CART.length === 0) return;
  let msg = 'Hi FMD,%0A%0AI%27d like to place an order%3A%0A%0A';
  CART.forEach(i=>{
    const p = PRODUCTS[i.id]; if (!p) return;
    msg += '• ' + i.qty + ' × ' + p.brand + ' ' + p.title + ' — R ' + (p.price*i.qty).toLocaleString() + '%0A';
  });
  const subtotal = CART.reduce((s,i)=>{const p=PRODUCTS[i.id];return s+(p?p.price*i.qty:0);}, 0);
  msg += '%0ATotal%3A R ' + subtotal.toLocaleString() + '%0A%0A';
  if (USER){ msg += 'Name%3A ' + encodeURIComponent(USER.name) + '%0APhone%3A ' + encodeURIComponent(USER.phone) + '%0AEmail%3A ' + encodeURIComponent(USER.email) + '%0A'; }
  msg += '%0AThanks!';
  window.open('https://wa.me/27817033912?text=' + msg, '_blank');
}

function checkoutEmail(){
  if (CART.length === 0) return;
  let body = 'Hi FMD,%0D%0A%0D%0AI would like to place an order:%0D%0A%0D%0A';
  CART.forEach(i=>{
    const p = PRODUCTS[i.id]; if (!p) return;
    body += '- ' + i.qty + ' x ' + p.brand + ' ' + p.title + ' - R ' + (p.price*i.qty).toLocaleString() + '%0D%0A';
  });
  const subtotal = CART.reduce((s,i)=>{const p=PRODUCTS[i.id];return s+(p?p.price*i.qty:0);}, 0);
  body += '%0D%0ATotal: R ' + subtotal.toLocaleString() + '%0D%0A%0D%0AThanks!';
  window.location.href = 'mailto:admin@fmdelectrical.co.za?subject=Online%20Order&body=' + body;
}

function renderAccount(){
  const content = document.getElementById('accountContent');
  const title = document.getElementById('accountTitle');
  if (USER){
    title.textContent = 'Welcome back, ' + USER.name.split(' ')[0];
    content.innerHTML = '<div style="max-width:720px;margin:0 auto"><div class="welcome-card"><strong>👋 ' + USER.name + '</strong><span>Logged in</span></div><div class="auth-card"><h2 style="font-size:1.2rem">My Details</h2><dl style="margin:1rem 0"><div class="profile-row"><dt>Name</dt><dd>' + USER.name + '</dd></div><div class="profile-row"><dt>Email</dt><dd>' + USER.email + '</dd></div><div class="profile-row"><dt>Phone</dt><dd>' + USER.phone + '</dd></div></dl><button onclick="logoutUser()" class="btn btn-outline" style="width:100%">Log Out</button></div></div>';
  } else {
    title.textContent = 'My Account';
    content.innerHTML = '<div class="auth-grid"><div class="auth-card"><h2>Create Account</h2><p>Save your contact details for faster checkout.</p><form onsubmit="createUser(event)"><div class="form-field"><label>Full Name *</label><input type="text" id="rName" required></div><div class="form-field"><label>Email *</label><input type="email" id="rEmail" required></div><div class="form-field"><label>Phone *</label><input type="tel" id="rPhone" required></div><div class="form-field"><label>Address (optional)</label><textarea id="rAddress" rows="2"></textarea></div><button type="submit" class="btn btn-primary">Create Account</button></form></div><div class="auth-card"><h2>Already a Customer?</h2><p>Enter your email to retrieve saved details.</p><form onsubmit="loginUser(event)"><div class="form-field"><label>Email *</label><input type="email" id="lEmail" required></div><button type="submit" class="btn btn-dark">Restore My Details</button></form></div></div>';
  }
}

function createUser(e){
  e.preventDefault();
  USER = {name: document.getElementById('rName').value, email: document.getElementById('rEmail').value, phone: document.getElementById('rPhone').value, address: document.getElementById('rAddress').value};
  saveUser();
  showToast('Account created');
  setTimeout(renderAccount, 500);
}
function loginUser(e){
  e.preventDefault();
  const email = document.getElementById('lEmail').value;
  if (USER && USER.email === email){ showToast('Welcome back!'); renderAccount(); }
  else { showToast('No saved account with that email'); }
}
function logoutUser(){
  if (confirm('Clear saved details?')){ USER = null; localStorage.removeItem('fmd_user'); renderAccount(); showToast('Logged out'); }
}

function submitQuote(e){
  e.preventDefault();
  const d = {n:document.getElementById('qName').value, p:document.getElementById('qPhone').value, e:document.getElementById('qEmail').value, t:document.getElementById('qType').value, s:document.getElementById('qSuburb').value, m:document.getElementById('qMsg').value};
  const body = 'Hi FMD,%0D%0A%0D%0AI%27d like a quote.%0D%0A%0D%0AName: ' + d.n + '%0D%0APhone: ' + d.p + '%0D%0AEmail: ' + d.e + '%0D%0AType: ' + d.t + '%0D%0ASuburb: ' + d.s + '%0D%0A%0D%0ADetails:%0D%0A' + encodeURIComponent(d.m);
  window.location.href = 'mailto:admin@fmdelectrical.co.za?subject=Quote%20Request&body=' + body;
  showToast('Quote sent');
}

function submitLeadCapture(e){
  e.preventDefault();
  const d = {n:document.getElementById('lcName').value, p:document.getElementById('lcPhone').value, e:document.getElementById('lcEmail').value, t:document.getElementById('lcType').value, s:document.getElementById('lcSuburb').value, m:document.getElementById('lcMsg').value};
  const body = 'Hi FMD,%0D%0A%0D%0AI%27d like a quote.%0D%0A%0D%0AName: ' + d.n + '%0D%0APhone: ' + d.p + '%0D%0AEmail: ' + d.e + '%0D%0AType: ' + d.t + '%0D%0ASuburb: ' + d.s + '%0D%0A%0D%0ADetails:%0D%0A' + encodeURIComponent(d.m);
  window.location.href = 'mailto:admin@fmdelectrical.co.za?subject=Quote%20Request&body=' + body;
  showToast('Quote sent');
}

function scrollToCat(cat){ const el = document.getElementById('cat-' + cat); if (el) el.scrollIntoView({behavior:'smooth',block:'start'}); }

function showPage(name){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  const target = document.getElementById('page-'+name);
  if (target) target.classList.add('active');
  document.querySelectorAll('[data-nav]').forEach(a=>a.classList.toggle('active', a.dataset.nav===name));
  document.querySelectorAll('[data-mnav]').forEach(a=>a.classList.toggle('active', a.dataset.mnav===name));
  window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;
  if (name==='cart') renderCart();
  if (name==='account') renderAccount();
  if (name==='shop') paintProductImages();
}

function showBlogPost(slug){
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  const target = document.getElementById('page-blog-'+slug);
  if (target) target.classList.add('active');
  document.querySelectorAll('[data-nav]').forEach(a=>a.classList.toggle('active', a.dataset.nav==='blog'));
  window.scrollTo(0,0);document.documentElement.scrollTop=0;document.body.scrollTop=0;
}

function closeDrawer(){
  document.getElementById('mDrawer').classList.remove('open');
  document.getElementById('mOverlay').classList.remove('open');
  document.body.style.overflow = '';
}

document.getElementById('mOpen').addEventListener('click',()=>{
  document.getElementById('mDrawer').classList.add('open');
  document.getElementById('mOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
});
document.getElementById('mClose').addEventListener('click', closeDrawer);
document.getElementById('mOverlay').addEventListener('click', closeDrawer);

const io = new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting){e.target.classList.add('in');io.unobserve(e.target)}}), {threshold:.1, rootMargin:'0px 0px -60px 0px'});
document.querySelectorAll('.reveal').forEach(el=>io.observe(el));

const cio = new IntersectionObserver(es=>es.forEach(e=>{
  if(e.isIntersecting){
    const el=e.target, t=+el.dataset.target;
    const small = el.querySelector('small') ? el.querySelector('small').outerHTML : '';
    let s = performance.now();
    function tick(n){
      const p = Math.min((n-s)/1600, 1);
      el.innerHTML = Math.floor(t*(1-Math.pow(1-p,3))).toLocaleString() + small;
      if (p<1) requestAnimationFrame(tick);
    }
    requestAnimationFrame(tick); cio.unobserve(el);
  }
}), {threshold:.5});
document.querySelectorAll('.counter-n').forEach(el=>cio.observe(el));

updateBadges();
renderCart();
renderAccount();
paintProductImages();


/* ── Navigation Event Delegation ── */
(function(){
  function wire(){
    document.querySelectorAll('[data-page]').forEach(function(el){
      el.addEventListener('click',function(e){
        e.preventDefault();
        showPage(el.getAttribute('data-page'));
        var d=document.getElementById('mDrawer');
        if(d&&d.classList.contains('open'))closeDrawer();
      });
    });
    document.querySelectorAll('[data-blog]').forEach(function(el){
      el.addEventListener('click',function(e){
        e.preventDefault();
        showBlogPost(el.getAttribute('data-blog'));
        var d=document.getElementById('mDrawer');
        if(d&&d.classList.contains('open'))closeDrawer();
      });
    });
  }
  if(document.readyState==='loading'){
    document.addEventListener('DOMContentLoaded',wire);
  }else{wire();}
})();

